<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted } from 'vue'
import { ElMessage } from 'element-plus'
import { Pouring, Brush, FirstAidKit, Timer, DataAnalysis, CircleCheck, Refresh, Cpu, ArrowUp, ArrowDown } from '@element-plus/icons-vue'

// ==================== DCS 数据 ====================
const dcsAutoRefresh = ref(true)
const dcsLastUpdate = ref('')

interface HistoryItem {
  time: string
  value: number
}

interface DCSItem {
  current: number
  trend: number
  total: number
  rate: number
  history: HistoryItem[]
}

interface DCSData {
  baseGlue: DCSItem
  coloringLiquid: DCSItem
}

const dcsData = ref<DCSData>({
  baseGlue: {
    current: 1250.5,
    trend: 5.2,
    total: 8560.3,
    rate: 45.6,
    history: []
  },
  coloringLiquid: {
    current: 680.2,
    trend: -2.1,
    total: 4250.8,
    rate: 28.3,
    history: []
  }
})

// 生成历史数据
const generateHistoryData = (baseValue: number, count: number): HistoryItem[] => {
  const data: HistoryItem[] = []
  const now = new Date()
  for (let i = count - 1; i >= 0; i--) {
    const time = new Date(now.getTime() - i * 5 * 60000)
    data.push({
      time: `${time.getHours().toString().padStart(2, '0')}:${time.getMinutes().toString().padStart(2, '0')}`,
      value: Math.round((baseValue + (Math.random() - 0.5) * 400) * 10) / 10
    })
  }
  return data
}

// ==================== 批控数据 ====================
const batchLastUpdate = ref('')

interface Reactor {
  id: string
  name: string
  status: string
  statusText: string
  statusType: 'success' | 'warning' | 'info' | 'primary' | 'danger'
  temperature: number
  pressure: number
  rpm: number
  progress: number
  progressStatus: '' | 'success' | 'exception' | 'warning'
}

interface FeedingItem {
  material: string
  batchNo: string
  target: number
  actual: number
}

interface LineOutput {
  name: string
  value: number
}

interface BatchData {
  reactors: Reactor[]
  feeding: FeedingItem[]
  output: {
    today: number
    compare: number
    byLine: LineOutput[]
  }
}

const batchData = ref<BatchData>({
  reactors: [
    {
      id: 'R001',
      name: '反应釜 #1',
      status: 'running',
      statusText: '运行中',
      statusType: 'success',
      temperature: 85.5,
      pressure: 0.35,
      rpm: 120,
      progress: 78,
      progressStatus: ''
    },
    {
      id: 'R002',
      name: '反应釜 #2',
      status: 'running',
      statusText: '运行中',
      statusType: 'success',
      temperature: 92.3,
      pressure: 0.42,
      rpm: 150,
      progress: 45,
      progressStatus: ''
    },
    {
      id: 'R003',
      name: '反应釜 #3',
      status: 'idle',
      statusText: '待机',
      statusType: 'warning',
      temperature: 25.0,
      pressure: 0.1,
      rpm: 0,
      progress: 0,
      progressStatus: ''
    }
  ],
  feeding: [
    { material: '基胶A-001', batchNo: 'BT20240605001', target: 1000, actual: 1000 },
    { material: '固化剂B-002', batchNo: 'BT20240605002', target: 500, actual: 485 },
    { material: '填料C-003', batchNo: 'BT20240605003', target: 800, actual: 320 },
    { material: '助剂D-004', batchNo: 'BT20240605004', target: 200, actual: 200 }
  ],
  output: {
    today: 2580,
    compare: 12.5,
