const getTempClass = (temp: number): string => {
  if (temp > 90) return 'temp-high'
  if (temp > 80) return 'temp-normal'
  return 'temp-low'
}

const updateTime = () => {
  const now = new Date()
  const timeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}:${now.getSeconds().toString().padStart(2, '0')}`
  dcsLastUpdate.value = timeStr
  batchLastUpdate.value = timeStr
}

const refreshAllData = () => {
  // 模拟刷新数据
  dcsData.value.baseGlue.current = Math.round((1200 + Math.random() * 200) * 10) / 10
  dcsData.value.baseGlue.trend = Math.round((Math.random() - 0.5) * 10 * 10) / 10
  dcsData.value.coloringLiquid.current = Math.round((600 + Math.random() * 200) * 10) / 10
  dcsData.value.coloringLiquid.trend = Math.round((Math.random() - 0.5) * 10 * 10) / 10
  
  // 更新历史数据
  dcsData.value.baseGlue.history = generateHistoryData(1250, 12)
  dcsData.value.coloringLiquid.history = generateHistoryData(680, 12)
  
  updateTime()
  ElMessage.success('数据已刷新')
}

const syncBatchData = () => {
  updateTime()
  ElMessage.success('批控数据已同步')
}

const submitNewRecord = () => {
  const now = new Date()
  const timeStr = `${now.getHours().toString().padStart(2, '0')}:${now.getMinutes().toString().padStart(2, '0')}`
  
  if (newRecord.value.type === 'powder') {
    manualData.value.powderRecords.unshift({
      time: timeStr,
      material: newRecord.value.material,
      batchNo: newRecord.value.batchNo,
      quantity: newRecord.value.quantity,
      operator: '当前用户',
      status: '待确认'
    })
  } else {
    manualData.value.productionReports.unshift({
      time: timeStr,
      workOrder: newRecord.value.workOrder,
      product: newRecord.value.product,
      quantity: newRecord.value.quantity,
      reporter: '当前用户',
      status: '待审核'
    })
  }
  
  showAddDialog.value = false
  ElMessage.success('记录已添加')
  
  // 重置表单
  newRecord.value = {
    type: 'powder',
    material: '',
    batchNo: '',
    workOrder: '',
    product: '',
    quantity: 0
  }
}

