}

const exportProductionReports = () => {
  ElMessage.info('报产报表导出功能开发中...')
}

// ==================== 自动刷新 ====================
let refreshTimer: number | null = null

onMounted(() => {
  // 初始化历史数据
  dcsData.value.baseGlue.history = generateHistoryData(1250, 12)
  dcsData.value.coloringLiquid.history = generateHistoryData(680, 12)
  updateTime()
  
  // 启动自动刷新
  refreshTimer = window.setInterval(() => {
    if (dcsAutoRefresh.value) {
      dcsData.value.baseGlue.current = Math.round((dcsData.value.baseGlue.current + (Math.random() - 0.5) * 50) * 10) / 10
      dcsData.value.coloringLiquid.current = Math.round((dcsData.value.coloringLiquid.current + (Math.random() - 0.5) * 30) * 10) / 10
      updateTime()
    }
  }, 5000)
})

onUnmounted(() => {
  if (refreshTimer) {
    clearInterval(refreshTimer)
  }
})
